export interface YieldExpressionConfig {
  children?: NodeData[];
}

export type YieldExpressionNode = NodeData<'yield_expression'> & {
  children(...value: NodeData[]): YieldExpressionNode;
  render(): string;
  toEdit(start: number, end: number): Edit;
  toEdit(range: { start: { index: number }, end: { index: number } }): Edit;
  replace(target: { type: 'yield_expression'; range(): { start: { index: number }; end: { index: number } } }): Edit;
};

export function yieldExpression(
  config?: YieldExpressionConfig,
): YieldExpressionNode {
  const fields: any = config ?? {};
  const node: any = { type: 'yield_expression', fields };
  node.children = (...v: any[]) => { fields.children = v; return node; };
  node.render = () => render(node, rules, joinBy);
  node.toEdit = (startOrRange: any, endPos?: number) => toEdit(node, rules, startOrRange, endPos, joinBy);
  node.replace = (target: any) => { const r = target.range(); return toEdit(node, rules, r, undefined, joinBy); };
  return node;
}

yieldExpression.assign = function(target: AssignableNode<'yield_expression'>): YieldExpressionNode {
  const overrides: any = {};
  const fieldList = [];
  const getFields = () => {
    const merged: any = {};
    for (const f of fieldList) {
      if (f in overrides) { merged[f] = overrides[f]; continue; }
      const child = target.field(f);
      if (child) merged[f] = { type: child.type, fields: {}, text: child.text() };
    }
    if ('children' in overrides) { merged.children = overrides.children; }
    else { merged.children = target.children().map(c => ({ type: c.type, fields: {}, text: c.text() })); }
    return merged;
  };
  const node: any = { get type() { return 'yield_expression'; }, get fields() { return getFields(); } };
  node.children = (...v: any[]) => { overrides.children = v; return node; };
  node.render = () => render(node, rules, joinBy);
  node.toEdit = () => {
    const r = target.range();
    return { startPos: r.start.index, endPos: r.end.index, insertedText: node.render() };
  };
  node.replace = node.toEdit;
  return node;
} as any;

